use std::sync::{Arc, Mutex};
use std::thread;

fn main() {
    let count = Arc::new(Mutex::new(1));
    let worker_count = Arc::clone(&count);
    let handle = thread::spawn(move || {
        *worker_count.lock().unwrap() += 1;
    });
    handle.join().unwrap();
    println!("example:{}", *count.lock().unwrap());
}

